SELECT id, name, full_name, description, url, language, team, enabled, created_at, updated_at, deleted
FROM repo
WHERE deleted = false
AND name LIKE CONCAT('%', #{name}, '%')
AND team = #{team}
AND enabled = #{enabled}
ORDER BY created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM repo
WHERE deleted = false
AND name LIKE CONCAT('%', #{name}, '%')
AND team = #{team}
AND enabled = #{enabled}
